const ProjectCard = styled(motion.div)`
  position: relative;
  background: linear-gradient(145deg, rgba(26, 0, 51, 0.8), rgba(13, 0, 21, 0.95));
  border-radius: 28px;
  overflow: hidden;
  cursor: pointer;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  backdrop-filter: blur(10px);
  border: 1px solid rgba(153, 69, 255, 0.15);
  display: flex;
  flex-direction: column;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
  will-change: transform;
  
  &::before {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(145deg, rgba(153, 69, 255, 0.03), transparent);
    border-radius: inherit;
    z-index: 0;
  }
  
  &:hover {
    transform: translateY(-16px) scale(1.02);
    box-shadow: 0 32px 64px rgba(153, 69, 255, 0.25), 0 0 0 1px rgba(153, 69, 255, 0.3);
    border-color: rgba(153, 69, 255, 0.4);
    
    &::before {
      background: linear-gradient(145deg, rgba(153, 69, 255, 0.08), rgba(255, 255, 255, 0.02));
    }
    
    .project-image {
      background: linear-gradient(145deg, rgba(153, 69, 255, 0.15), rgba(13, 0, 21, 0.9));
      border-bottom-color: rgba(153, 69, 255, 0.4);
    }
    
    .project-image img {
      transform: scale(1.05);
    }
    
    .project-overlay {
      opacity: 0.8;
    }
  }
  
  @media (max-width: 768px) {
    border-radius: 20px;
    
    &:hover {
      transform: translateY(-8px) scale(1.01);
    }
  }
`;

