const Clients = () => {
  const sectionRef = useRef(null);
  const headerRef = useRef(null);
  const gridRef = useRef(null);
  const [allClients] = useState(clientsData);
  const [imageAspectRatios, setImageAspectRatios] = useState({});

  const handleImageLoad = (clientId, event) => {
    const img = event.target;
    const aspectRatio = img.naturalWidth / img.naturalHeight;
    setImageAspectRatios(prev => ({
      ...prev,
      [clientId]: aspectRatio
    }));
  };

  const getMaxWidth = (clientId, isLogo) => {
    const aspectRatio = imageAspectRatios[clientId];
    if (!aspectRatio || !isLogo) return 'calc(100% - 20px)';
    
    // If aspect ratio is close to square (between 0.8 and 1.2), limit width
    if (aspectRatio >= 0.8 && aspectRatio <= 1.2) {
      return '200px';
    }
    // For wider images, allow full width
    return 'calc(100% - 20px)';
  };

  const getStats = () => {
    const activeClients = clientsData.filter(client => client.status === 'Active');
    const totalPlayers = clientsData.reduce((sum, client) => {
      const playerCount = parseInt(client.players.replace(/[^0-9]/g, '')) || 0;
      return sum + playerCount;
    }, 0);
    
    return {
      total: clientsData.length,
      active: activeClients.length,
      countries: [...new Set(clientsData.map(client => client.location))].length,
      players: `${(totalPlayers / 1000).toFixed(1)}k+`
    };
  };


  useLayoutEffect(() => {
    const initializeClientAnimations = () => {
      const section = sectionRef.current;
      const header = headerRef.current;
      const grid = gridRef.current;

      if (!section || !header) return;

      // Simple header fade-in
      gsap.fromTo(header,
        { opacity: 0, y: 20 },
        { 
          opacity: 1, 
          y: 0, 
          duration: 0.6, 
          ease: 'power2.out',
          scrollTrigger: {
            trigger: header,
            start: 'top 90%',
            once: true,
            refreshPriority: 5,
            fastScrollEnd: true,
            preventOverlaps: true,
            invalidateOnRefresh: true
          }
        }
      );

      // Simple card reveal with Intersection Observer for better performance
      if (grid) {
        const cards = grid.querySelectorAll('.client-card');
        
        const observer = new IntersectionObserver((entries) => {
          entries.forEach((entry, index) => {
            if (entry.isIntersecting) {
              gsap.fromTo(entry.target,
                { opacity: 0, y: 30 },
                { 
                  opacity: 1, 
                  y: 0, 
                  duration: 0.5,
                  ease: 'power2.out',
                  delay: index * 0.05
                }
              );
              observer.unobserve(entry.target);
            }
          });
        }, { threshold: 0.1 });

        cards.forEach(card => observer.observe(card));
      }

      return () => {
        ScrollTrigger.getAll().forEach(trigger => trigger.kill());
      };
    };

    // Use requestAnimationFrame for better build performance
    requestAnimationFrame(() => {
      setTimeout(initializeClientAnimations, 50);
    });
  }, [allClients]);

  return (
    <ClientsSection ref={sectionRef}>
      <BackgroundElements>
        <GridPattern />
        <FloatingOrb 
          className="floating-orb"
          style={{ 
            top: '8%', 
            left: '5%', 
            width: '350px', 
            height: '350px' 
          }}
        />
        <FloatingOrb 
          className="floating-orb"
          style={{ 
            bottom: '8%', 
            right: '5%', 
            width: '300px', 
            height: '300px' 
          }}
        />
      </BackgroundElements>

      <Container>
        <Header ref={headerRef}>
          <SectionLabel className="section-label">
            Clients
          </SectionLabel>
          <Title className="title">
            My Clients
          </Title>
          <Subtitle className="subtitle">
            Overview
          </Subtitle>
        </Header>

        <StatsContainer>
          <StatCard>
            <StatNumber>{getStats().total}</StatNumber>
            <StatLabel>Clients</StatLabel>
          </StatCard>
          <StatCard>
            <StatNumber>{getStats().active}</StatNumber>
            <StatLabel>Of which active</StatLabel>
          </StatCard>
          <StatCard>
            <StatNumber>{getStats().countries}</StatNumber>
            <StatLabel>Countries</StatLabel>
          </StatCard>
          <StatCard>
            <StatNumber>{getStats().players}</StatNumber>
            <StatLabel>Players</StatLabel>
          </StatCard>
        </StatsContainer>


        <PortfolioGrid ref={gridRef}>
          <AnimatePresence mode="wait">
            {allClients.map((client, index) => (
              <ProjectCard
                key={client.id}
                className="client-card"
                as="a"
                href={client.link}
                target="_blank"
                rel="noopener noreferrer"
                initial={{ opacity: 1 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                transition={{ 
                  duration: 0.2
                }}
                style={{
                  textDecoration: 'none',
                  color: 'inherit'
                }}
              >
                <ProjectImage className="project-image">
                  <div className="image-container">
                    <OptimizedImage 
                      src={getImagePath(client.imageName)} 
                      webpSrc={getOptimizedImagePath(client.imageName)}
                      alt={client.title}
                      objectFit="contain"
                      objectPosition="center"
                      loading="lazy"
                      onLoad={(e) => handleImageLoad(client.id, e)}
                      wrapperStyle={{
                        width: '100%',
                        height: '100%',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center'
                      }}
                      style={{ 
                        width: 'auto',
                        height: 'auto',
                        maxWidth: getMaxWidth(client.id, client.isLogo),
                        maxHeight: 'calc(100% - 30px)',
                        background: 'radial-gradient(circle at center, rgba(153, 69, 255, 0.05), transparent 70%)',
                        borderRadius: '12px',
                        padding: '15px',
                        filter: 'drop-shadow(0 4px 20px rgba(0, 0, 0, 0.3))'
                      }}
                    />
                  </div>
                  <ProjectOverlay className="project-overlay" />
                  <ProjectHeader>
                    <ProjectYear>{client.year}</ProjectYear>
                  </ProjectHeader>
                </ProjectImage>
                
                <ProjectContent>
                  <div>
                    <ProjectTitle>{client.title}</ProjectTitle>
                    <ProjectInfo>
                      <ProjectPlatform>{client.platform}</ProjectPlatform>
                      <ProjectCategory>{client.category}</ProjectCategory>
                    </ProjectInfo>
                    <ProjectDescription>
                      {client.description}
                    </ProjectDescription>
                  </div>
                  
                  <ProjectStats>
                    <StatItem>
                      {client.location}
                    </StatItem>
                    <StatItem>
                      <span>👥</span>
                      {client.players}
                    </StatItem>
                    <StatusIndicator status={client.status}>
                      {client.status}
                    </StatusIndicator>
                  </ProjectStats>
                </ProjectContent>
              </ProjectCard>
            ))}
          </AnimatePresence>
        </PortfolioGrid>
      </Container>
    </ClientsSection>
  );
};

export default Clients;