import React, { useState, useEffect, useRef } from 'react';
import styled from 'styled-components';

const ImageWrapper = styled.div`
  position: relative;
  overflow: hidden;
  background-color: ${props => props.$background || 'rgba(153, 69, 255, 0.05)'};
`;

const StyledImage = styled.img`
  width: 100%;
  height: 100%;
  object-fit: ${props => props.$objectFit || 'cover'};
  object-position: ${props => props.$objectPosition || 'center'};
  transition: opacity 0.3s ease;
  opacity: ${props => props.$loaded ? 1 : 0};
`;

const PlaceholderDiv = styled.div`
  position: absolute;
  inset: 0;
  background: ${props => props.$placeholderBg || 'linear-gradient(45deg, rgba(153, 69, 255, 0.1), rgba(88, 101, 242, 0.1))'};
  filter: blur(20px);
  transform: scale(1.1);
`;

const OptimizedImage = ({ 
  src, 
  alt, 
  width, 
  height, 
  loading = 'lazy',
  objectFit = 'cover',
  objectPosition = 'center',
  placeholderBg,
  className,
  style,
  wrapperStyle,
  onLoad,
  webpSrc,
  ...props 
}) => {
  const [loaded, setLoaded] = useState(false);
  const [inView, setInView] = useState(false);
  const imgRef = useRef(null);

  useEffect(() => {
    if (!imgRef.current || loading !== 'lazy') return;

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            setInView(true);
            observer.unobserve(entry.target);
          }
        });
      },
      { 
        rootMargin: '50px',
        threshold: 0.01 
      }
    );

    const element = imgRef.current;
    if (element) {
      observer.observe(element);
    }

    return () => {
      if (element) {
        observer.unobserve(element);
      }
    };
  }, [loading]);

  const handleLoad = (e) => {
    setLoaded(true);
    if (onLoad) onLoad(e);
  };

  const shouldLoad = loading === 'lazy' ? inView : true;

  return (
    <ImageWrapper 
      ref={imgRef} 
      className={className} 
      style={{ width, height, ...style, ...wrapperStyle }}
      $background={placeholderBg}
    >
      {!loaded && <PlaceholderDiv $placeholderBg={placeholderBg} />}
      {shouldLoad && (
        webpSrc ? (
          <picture>
            <source srcSet={webpSrc} type="image/webp" />
            <StyledImage
              src={src}
              alt={alt}
              width={typeof width === 'number' ? width : undefined}
              height={typeof height === 'number' ? height : undefined}
              loading={loading}
              onLoad={handleLoad}
              $loaded={loaded}
              $objectFit={objectFit}
              $objectPosition={objectPosition}
              {...props}
            />
          </picture>
        ) : (
          <StyledImage
            src={src}
            alt={alt}
            width={typeof width === 'number' ? width : undefined}
            height={typeof height === 'number' ? height : undefined}
            loading={loading}
            onLoad={handleLoad}
            $loaded={loaded}
            $objectFit={objectFit}
            $objectPosition={objectPosition}
            {...props}
          />
        )
      )}
    </ImageWrapper>
  );
};

export default OptimizedImage;